async def get_embedding(client: openai.AsyncOpenAI, text: str) -> list[float]:
    response = await client.embeddings.create(
        model=EMBED_MODEL,
        input=text,
    )
    return response.data[0].embedding


async def seed_collection(
    qdrant: AsyncQdrantClient,
    oai: openai.AsyncOpenAI,
    collection: str,
    entries: list[tuple[str, str]],
    batch_size: int = 5,
) -> None:
    print(f"\n{'='*60}")
    print(f"Seeding {collection} ({len(entries)} entries)...")

    existing, _ = await qdrant.scroll(
        collection_name=collection,
        limit=1,
        with_payload=False,
        with_vectors=False,
    )
    if existing:
        print(f"  Collection has existing data. Adding to it.")

    points = []
    for i, (topic, text) in enumerate(entries):
        print(f"  [{i+1}/{len(entries)}] Embedding: {topic[:50]}")
        embedding = await get_embedding(oai, f"{topic}\n{text}")
        points.append(PointStruct(
            id=str(uuid.uuid4()),
            vector=embedding,
            payload={"topic": topic, "text": text, "collection": collection},
        ))

        if len(points) >= batch_size:
            await qdrant.upsert(collection_name=collection, points=points)
            print(f"    Uploaded batch of {len(points)}")
            points = []
            time.sleep(0.3)

    if points:
        await qdrant.upsert(collection_name=collection, points=points)
        print(f"    Uploaded final batch of {len(points)}")

    info = await qdrant.get_collection(collection)
    print(f"  Done. Total points: {info.points_count}")


async def main(collections: list[str]) -> None:
    if not OPENAI_KEY:
        print("ERROR: OPENAI_API_KEY not set")
        sys.exit(1)

    oai = openai.AsyncOpenAI(api_key=OPENAI_KEY)
    qdrant = AsyncQdrantClient(url=QDRANT_URL)

    try:
        if "tarot" in collections:
            await seed_collection(qdrant, oai, "knowledge_tarot", TAROT_ENTRIES)
        if "astro" in collections:
            await seed_collection(qdrant, oai, "knowledge_astro", ASTRO_ENTRIES)
        if "psych" in collections:
            await seed_collection(qdrant, oai, "knowledge_psych", PSYCH_ENTRIES)
    finally:
        await qdrant.close()
        await oai.close()

    print("\nDone!")


if __name__ == "__main__":
    parser = argparse.ArgumentParser()
    parser.add_argument(
        "--collection",
        choices=["tarot", "astro", "psych", "all"],
        default="all",
    )
    args = parser.parse_args()

    cols = ["tarot", "astro", "psych"] if args.collection == "all" else [args.collection]
    asyncio.run(main(cols))
